using System;using System.Collections.Generic;using System.Drawing;using System.Windows.Forms;
namespace PremiumLivingFurnitureWinForms;
public class PurchaseOrderForm:Form{readonly TextBox poNo=new();readonly ComboBox supplier=new(){DropDownStyle=ComboBoxStyle.DropDownList},item=new(){DropDownStyle=ComboBoxStyle.DropDownList},relatedOrder=new(){DropDownStyle=ComboBoxStyle.DropDownList},status=new(){DropDownStyle=ComboBoxStyle.DropDownList};readonly NumericUpDown qty=new(){Minimum=1,Maximum=999999,Value=1},unitCost=new(){Minimum=0,Maximum=999999999,DecimalPlaces=2,Increment=10};readonly DateTimePicker orderDate=new(){Format=DateTimePickerFormat.Short,Value=DateTime.Today},expectedDate=new(){Format=DateTimePickerFormat.Short,Value=DateTime.Today.AddDays(14)};readonly Label hint=new(),total=new();public Dictionary<string,object?> Values{get;}=new();public PurchaseOrderForm(){Text="Add Purchase Order";StartPosition=FormStartPosition.CenterParent;Size=new Size(850,650);Font=Theme.DefaultFont;BackColor=Theme.AppBg;poNo.ReadOnly=true;poNo.Text=Database.GenerateNextCode("PurchaseOrders","PONo","PO","-",4);poNo.BackColor=Theme.PrimarySoft;status.Items.AddRange(new object[]{"Request","Approved","Supplier Confirmed","Received","Cancelled"});status.SelectedIndex=0;var root=new TableLayoutPanel{Dock=DockStyle.Fill,ColumnCount=2,Padding=new Padding(26),BackColor=Theme.AppBg,AutoScroll=true};root.ColumnStyles.Add(new ColumnStyle(SizeType.Absolute,240));root.ColumnStyles.Add(new ColumnStyle(SizeType.Percent,100));AddRow(root,"PO No",poNo);AddRow(root,"Supplier",supplier);AddRow(root,"Supplier Item",item);AddRow(root,"Related Sales Order",relatedOrder);AddRow(root,"Quantity",qty);AddRow(root,"Unit Cost",unitCost);AddRow(root,"Status",status);AddRow(root,"Order Date",orderDate);AddRow(root,"Expected Date",expectedDate);hint.ForeColor=Theme.Muted;hint.Font=new Font("Segoe UI",9,FontStyle.Bold);hint.Dock=DockStyle.Fill;root.RowStyles.Add(new RowStyle(SizeType.Absolute,44));root.SetColumnSpan(hint,2);root.Controls.Add(hint,0,root.RowCount++);total.ForeColor=Theme.Primary;total.Font=new Font("Segoe UI",11,FontStyle.Bold);total.Dock=DockStyle.Fill;total.TextAlign=ContentAlignment.MiddleRight;root.RowStyles.Add(new RowStyle(SizeType.Absolute,44));root.SetColumnSpan(total,2);root.Controls.Add(total,0,root.RowCount++);var buttons=new FlowLayoutPanel{Dock=DockStyle.Fill,FlowDirection=FlowDirection.RightToLeft,BackColor=Theme.AppBg};var save=Theme.PrimaryButton("Save PO",120);var cancel=Theme.SecondaryButton("Cancel",110);save.Click+=(_,_)=>Save();cancel.Click+=(_,_)=>DialogResult=DialogResult.Cancel;buttons.Controls.Add(save);buttons.Controls.Add(cancel);root.RowStyles.Add(new RowStyle(SizeType.Absolute,58));root.SetColumnSpan(buttons,2);root.Controls.Add(buttons,0,root.RowCount++);Controls.Add(root);LoadLookups();Wire();Recalc();}static void AddRow(TableLayoutPanel root,string label,Control input){int row=root.RowCount++;root.RowStyles.Add(new RowStyle(SizeType.Absolute,58));root.Controls.Add(new Label{Text=label,Dock=DockStyle.Fill,TextAlign=ContentAlignment.MiddleLeft,ForeColor=Theme.Muted,Font=new Font("Segoe UI",9,FontStyle.Bold)},0,row);input.Dock=DockStyle.Fill;input.Margin=new Padding(0,8,0,8);root.Controls.Add(input,1,row);}void LoadLookups(){supplier.Items.Clear();foreach(var s in Database.GetLookup("Suppliers"))supplier.Items.Add(s);if(supplier.Items.Count>0)supplier.SelectedIndex=0;relatedOrder.Items.Clear();relatedOrder.Items.Add(new LookupItem(0,"0 - No related sales order"));foreach(var o in Database.GetLookup("Orders"))relatedOrder.Items.Add(o);relatedOrder.SelectedIndex=0;LoadItems();}void Wire(){supplier.SelectedIndexChanged+=(_,_)=>LoadItems();item.SelectedIndexChanged+=(_,_)=>ApplyCost();qty.ValueChanged+=(_,_)=>Recalc();unitCost.ValueChanged+=(_,_)=>Recalc();}void LoadItems(){item.Items.Clear();int sid=supplier.SelectedItem is LookupItem s?s.Id:0;foreach(var i in Database.GetSupplierItemsForSupplier(sid))item.Items.Add(i);if(item.Items.Count>0){item.SelectedIndex=0;ApplyCost();hint.Text="Supplier item list is filtered by selected supplier.";}else{hint.Text="No supplier items found for this supplier.";unitCost.Value=0;}Recalc();}void ApplyCost(){if(item.SelectedItem is not LookupItem i)return;decimal cost=Database.GetSupplierItemUnitCost(i.Id);if(cost>=unitCost.Minimum&&cost<=unitCost.Maximum)unitCost.Value=cost;Recalc();}void Recalc(){total.Text=$"Estimated total: HK$ {(qty.Value*unitCost.Value):N2}";}void Save(){if(supplier.SelectedItem is not LookupItem s){MessageBox.Show("Please select a supplier.");return;}if(item.SelectedItem is not LookupItem si){MessageBox.Show("Please select a supplier item.");return;}int oid=relatedOrder.SelectedItem is LookupItem o?o.Id:0;Values.Clear();Values["PONo"]=poNo.Text.Trim();Values["SupplierId"]=s.Id;Values["SupplierItemId"]=si.Id;if(oid>0)Values["RelatedOrderId"]=oid;Values["Item"]=si.Display;Values["Quantity"]=(int)qty.Value;Values["UnitCost"]=unitCost.Value;Values["Status"]=status.Text;Values["OrderDate"]=orderDate.Value.ToString("yyyy-MM-dd");Values["ExpectedDate"]=expectedDate.Value.ToString("yyyy-MM-dd");DialogResult=DialogResult.OK;}}
